contracts/AgentRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract AgentRegistry {
    struct Agent {
        uint256 agentId;
        string name;
        string skills;
        string erc8004Id;
        address owner;
        uint256 registeredAt;
        bool exists;
    }

    uint256 public constant REGISTRATION_STAKE = 0.01 ether;
    uint256 public nextAgentId = 1;
    mapping(uint256 => Agent) private agents;

    event AgentRegistered(
        uint256 indexed agentId,
        string name,
        string skills,
        string erc8004Id,
        address indexed owner,
        uint256 registeredAt
    );

    function registerAgent(
        string calldata name,
        string calldata skills,
        string calldata erc8004Id
    ) external payable returns (uint256 agentId) {
        require(bytes(name).length > 0, "name required");
        require(msg.value >= REGISTRATION_STAKE, "stake required");
        agentId = nextAgentId++;
        agents[agentId] = Agent(agentId, name, skills, erc8004Id, msg.sender, block.timestamp, true);
        emit AgentRegistered(agentId, name, skills, erc8004Id, msg.sender, block.timestamp);
    }

    function getAgent(uint256 agentId) external view returns (Agent memory) {
        require(agents[agentId].exists, "agent missing");
        return agents[agentId];
    }

    function agentExists(uint256 agentId) external view returns (bool) {
        return agents[agentId].exists;
    }

    function ownerOf(uint256 agentId) external view returns (address) {
        require(agents[agentId].exists, "agent missing");
        return agents[agentId].owner;
    }
}

contracts/AtlasScore.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract AtlasScore {
    struct Score {
        uint256 successCount;
        uint256 failureCount;
        uint256 taskVolume;
        uint256 reliabilityScore;
    }

    address public verifier;
    address public immutable deployer;
    uint256 public constant MAX_POSITIVE_CREDIT_PER_PAIR = 3;
    mapping(uint256 => Score) public scores;
    mapping(uint256 => bool) public countedJobs;
    mapping(uint256 => mapping(address => uint256)) public positivePairCredits;

    event ScoreUpdated(
        uint256 indexed agentId,
        uint256 successCount,
        uint256 failureCount,
        uint256 taskVolume,
        uint256 reliabilityScore,
        uint256 indexed jobId
    );

    modifier onlyVerifier() {
        require(msg.sender == verifier, "only verifier");
        _;
    }

    constructor() {
        deployer = msg.sender;
    }

    function setVerifier(address verifier_) external {
        require(msg.sender == deployer, "only deployer");
        require(verifier_ != address(0), "verifier required");
        require(verifier == address(0), "verifier set");
        verifier = verifier_;
    }

    function recordVerifiedProof(uint256 agentId, uint256 jobId, address creator, address agentOwner) external onlyVerifier {
        if (countedJobs[jobId]) return;
        countedJobs[jobId] = true;
        if (creator == agentOwner) return;
        if (positivePairCredits[agentId][creator] >= MAX_POSITIVE_CREDIT_PER_PAIR) return;
        positivePairCredits[agentId][creator] += 1;

        Score storage score = scores[agentId];
        score.successCount += 1;
        score.taskVolume += 1;
        score.reliabilityScore = _computeReliability(score.successCount, score.failureCount, score.taskVolume);

        emit ScoreUpdated(agentId, score.successCount, score.failureCount, score.taskVolume, score.reliabilityScore, jobId);
    }

    function recordFailedProof(uint256 agentId, uint256 jobId) external onlyVerifier {
        if (countedJobs[jobId]) return;
        countedJobs[jobId] = true;

        Score storage score = scores[agentId];
        score.failureCount += 1;
        score.taskVolume += 1;
        score.reliabilityScore = _computeReliability(score.successCount, score.failureCount, score.taskVolume);

        emit ScoreUpdated(agentId, score.successCount, score.failureCount, score.taskVolume, score.reliabilityScore, jobId);
    }

    function _computeReliability(uint256 successCount, uint256 failureCount, uint256 taskVolume) private pure returns (uint256) {
        if (taskVolume == 0) return 0;
        uint256 successRate = (successCount * 100) / taskVolume;
        uint256 volumeComponent = taskVolume > 100 ? 100 : taskVolume;
        uint256 failurePenalty = (failureCount * 100) / taskVolume;
        uint256 base = (successRate * 80 + volumeComponent * 20) / 100;
        return failurePenalty >= base ? 0 : base - failurePenalty;
    }
}

contracts/JobManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

interface IAgentRegistry {
    function agentExists(uint256 agentId) external view returns (bool);
    function ownerOf(uint256 agentId) external view returns (address);
}

contract JobManager {
    enum Status {
        OPEN,
        ASSIGNED,
        COMPLETED,
        FAILED
    }

    struct Job {
        uint256 jobId;
        string description;
        uint256 reward;
        Status status;
        uint256 assignedAgentId;
        address creator;
        uint256 createdAt;
    }

    IAgentRegistry public agentRegistry;
    address public verifier;
    address public immutable deployer;
    uint256 public constant JOB_BOND = 0.005 ether;
    uint256 public nextJobId = 1;
    mapping(uint256 => Job) private jobs;

    event JobCreated(uint256 indexed jobId, string description, uint256 reward, address indexed creator);
    event JobAccepted(uint256 indexed jobId, uint256 indexed agentId, address indexed agentOwner);
    event JobCompleted(uint256 indexed jobId, uint256 indexed agentId);
    event JobFailed(uint256 indexed jobId, uint256 indexed agentId, bytes32 reasonHash);

    modifier onlyVerifier() {
        require(msg.sender == verifier, "only verifier");
        _;
    }

    constructor(address agentRegistry_) {
        agentRegistry = IAgentRegistry(agentRegistry_);
        deployer = msg.sender;
    }

    function setVerifier(address verifier_) external {
        require(msg.sender == deployer, "only deployer");
        require(verifier_ != address(0), "verifier required");
        require(verifier == address(0), "verifier set");
        verifier = verifier_;
    }

    function createJob(string calldata description, uint256 reward) external payable returns (uint256 jobId) {
        require(bytes(description).length > 0, "description required");
        require(msg.value >= JOB_BOND, "bond required");
        jobId = nextJobId++;
        jobs[jobId] = Job(jobId, description, reward, Status.OPEN, 0, msg.sender, block.timestamp);
        emit JobCreated(jobId, description, reward, msg.sender);
    }

    function acceptJob(uint256 jobId, uint256 agentId) external {
        Job storage job = jobs[jobId];
        require(job.jobId != 0, "job missing");
        require(job.status == Status.OPEN, "not open");
        require(agentRegistry.agentExists(agentId), "agent missing");
        address agentOwner = agentRegistry.ownerOf(agentId);
        require(msg.sender == agentOwner, "only agent owner");
        require(job.creator != agentOwner, "self dealing");
        job.status = Status.ASSIGNED;
        job.assignedAgentId = agentId;
        emit JobAccepted(jobId, agentId, agentOwner);
    }

    function markCompleted(uint256 jobId) external onlyVerifier {
        Job storage job = jobs[jobId];
        require(job.jobId != 0, "job missing");
        require(job.status == Status.ASSIGNED, "not assigned");
        job.status = Status.COMPLETED;
        emit JobCompleted(jobId, job.assignedAgentId);
    }

    function markFailed(uint256 jobId, bytes32 reasonHash) external onlyVerifier {
        Job storage job = jobs[jobId];
        require(job.jobId != 0, "job missing");
        require(job.status == Status.ASSIGNED, "not assigned");
        job.status = Status.FAILED;
        emit JobFailed(jobId, job.assignedAgentId, reasonHash);
    }

    function getJob(uint256 jobId) external view returns (Job memory) {
        require(jobs[jobId].jobId != 0, "job missing");
        return jobs[jobId];
    }

    function jobExists(uint256 jobId) external view returns (bool) {
        return jobs[jobId].jobId != 0;
    }

    function assignedAgent(uint256 jobId) external view returns (uint256) {
        return jobs[jobId].assignedAgentId;
    }

    function creatorOf(uint256 jobId) external view returns (address) {
        require(jobs[jobId].jobId != 0, "job missing");
        return jobs[jobId].creator;
    }

    function agentOwnerOf(uint256 agentId) external view returns (address) {
        return agentRegistry.ownerOf(agentId);
    }
}

contracts/ProofVerifier.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

interface IJobManager {
    function jobExists(uint256 jobId) external view returns (bool);
    function assignedAgent(uint256 jobId) external view returns (uint256);
    function creatorOf(uint256 jobId) external view returns (address);
    function agentOwnerOf(uint256 agentId) external view returns (address);
    function markCompleted(uint256 jobId) external;
    function markFailed(uint256 jobId, bytes32 reasonHash) external;
}

interface IAgentRegistryForProofs {
    function ownerOf(uint256 agentId) external view returns (address);
}

interface IAtlasScore {
    function recordVerifiedProof(uint256 agentId, uint256 jobId, address creator, address agentOwner) external;
    function recordFailedProof(uint256 agentId, uint256 jobId) external;
}

contract ProofVerifier {
    struct Proof {
        uint256 jobId;
        uint256 agentId;
        bytes32 resultHash;
        bool verified;
        bool submitted;
        uint256 verifiedAt;
    }

    IJobManager public jobManager;
    IAtlasScore public atlasScore;
    IAgentRegistryForProofs public agentRegistry;
    mapping(uint256 => Proof) public proofs;
    mapping(uint256 => bool) public verifiedJobs;
    mapping(uint256 => bool) public failedJobs;

    event ProofSubmitted(uint256 indexed jobId, uint256 indexed agentId, bytes32 resultHash);
    event ProofVerified(uint256 indexed jobId, uint256 indexed agentId, bytes32 resultHash);
    event ProofFailed(uint256 indexed jobId, uint256 indexed agentId, bytes32 reasonHash);

    constructor(address jobManager_, address atlasScore_, address agentRegistry_) {
        jobManager = IJobManager(jobManager_);
        atlasScore = IAtlasScore(atlasScore_);
        agentRegistry = IAgentRegistryForProofs(agentRegistry_);
    }

    function submitProof(uint256 jobId, uint256 agentId, bytes32 resultHash) external {
        require(jobManager.jobExists(jobId), "job missing");
        require(jobManager.assignedAgent(jobId) == agentId, "wrong agent");
        require(agentRegistry.ownerOf(agentId) == msg.sender, "only agent owner");
        require(resultHash != bytes32(0), "hash required");
        require(!proofs[jobId].submitted, "already submitted");
        require(!verifiedJobs[jobId], "already verified");
        require(!failedJobs[jobId], "already failed");

        proofs[jobId] = Proof(jobId, agentId, resultHash, false, true, 0);
        emit ProofSubmitted(jobId, agentId, resultHash);
    }

    function acceptProof(uint256 jobId, uint256 agentId) external {
        Proof storage proof = proofs[jobId];
        require(proof.submitted, "proof missing");
        require(proof.agentId == agentId, "wrong agent");
        require(jobManager.creatorOf(jobId) == msg.sender, "only job creator");
        require(!verifiedJobs[jobId], "already verified");
        require(!failedJobs[jobId], "already failed");

        proof.verified = true;
        proof.verifiedAt = block.timestamp;
        jobManager.markCompleted(jobId);
        verifiedJobs[jobId] = true;
        emit ProofVerified(jobId, agentId, proof.resultHash);
        atlasScore.recordVerifiedProof(agentId, jobId, msg.sender, jobManager.agentOwnerOf(agentId));
    }

    function markJobFailed(uint256 jobId, uint256 agentId, bytes32 reasonHash) external {
        require(jobManager.jobExists(jobId), "job missing");
        require(jobManager.assignedAgent(jobId) == agentId, "wrong agent");
        require(jobManager.creatorOf(jobId) == msg.sender, "only job creator");
        require(reasonHash != bytes32(0), "reason required");
        require(!verifiedJobs[jobId], "already verified");
        require(!failedJobs[jobId], "already failed");

        failedJobs[jobId] = true;
        jobManager.markFailed(jobId, reasonHash);
        emit ProofFailed(jobId, agentId, reasonHash);
        atlasScore.recordFailedProof(agentId, jobId);
    }
}

